# test_matrix_transpose.py

import pytest

# Replace `your_module` with the actual module name where matrix_transpose is defined
from your_module import matrix_transpose


@pytest.mark.parametrize(
    "matrix, expected",
    [
        (
            [[1, 2, 3], [4, 5, 6]],
            [[1, 4], [2, 5], [3, 6]],
        ),
        (
            [[1, 2], [3, 4]],
            [[1, 3], [2, 4]],
        ),
        (
            [[1, 2, 3]],
            [[1], [2], [3]],
        ),
        (
            [[1], [2], [3]],
            [[1, 2, 3]],
        ),
        (
            [["a", "b"], ["c", "d"]],
            [["a", "c"], ["b", "d"]],
        ),
    ],
)
def test_matrix_transpose_happy_paths(matrix, expected):
    assert matrix_transpose(matrix) == expected


def test_matrix_transpose_empty_matrix_returns_empty_list():
    assert matrix_transpose([]) == []


@pytest.mark.parametrize(
    "matrix",
    [
        [[]],
        [[], []],
        [[], [1, 2, 3]],
    ],
)
def test_matrix_transpose_empty_first_row_returns_empty_list(matrix):
    assert matrix_transpose(matrix) == []


def test_matrix_transpose_does_not_mutate_input():
    matrix = [[1, 2], [3, 4]]
    original = [row[:] for row in matrix]

    result = matrix_transpose(matrix)

    assert matrix == original
    assert result == [[1, 3], [2, 4]]


def test_matrix_transpose_ragged_matrix_with_longer_later_rows_ignores_extra_values():
    matrix = [[1], [2, 3], [4, 5, 6]]

    assert matrix_transpose(matrix) == [[1, 2, 4]]


@pytest.mark.parametrize(
    "matrix",
    [
        [[1, 2], [3]],
        [[1], []],
        [[1, 2, 3], [4, 5]],
    ],
)
def test_matrix_transpose_ragged_matrix_with_shorter_later_rows_raises_index_error(matrix):
    with pytest.raises(IndexError):
        matrix_transpose(matrix)


@pytest.mark.parametrize(
    "matrix",
    [
        [1, 2, 3],
        [[1], 2],
        [[1], None],
    ],
)
def test_matrix_transpose_invalid_row_types_raise_type_error(matrix):
    with pytest.raises(TypeError):
        matrix_transpose(matrix)
